import{_ as t,o,c as s,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const c=JSON.parse('{"title":"Résolution de Problèmes — Distributeurs","description":"","frontmatter":{"title":"Résolution de Problèmes — Distributeurs"},"headers":[],"relativePath":"docs/fr/faq/troubleshooting-distributors.md","filePath":"docs/fr/faq/troubleshooting-distributors.md"}'),n={name:"docs/fr/faq/troubleshooting-distributors.md"};function r(i,e,l,u,p,d){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="resolution-de-problemes-—-distributeurs" tabindex="-1">Résolution de Problèmes — Distributeurs <a class="header-anchor" href="#resolution-de-problemes-—-distributeurs" aria-label="Permalink to &quot;Résolution de Problèmes — Distributeurs&quot;">​</a></h1><p class="gi-page-intro">Votre Wallet ne correspond pas ? Un retrait tarde ? Une campagne pose problème ? Trouvez la réponse en moins de 2 minutes.</p><h2 id="💰-wallet-paiements" tabindex="-1">💰 Wallet &amp; Paiements <a class="header-anchor" href="#💰-wallet-paiements" aria-label="Permalink to &quot;💰 Wallet &amp; Paiements&quot;">​</a></h2><h3 id="mon-solde-disponible-est-a-0-alors-que-j-ai-distribue-des-campagnes" tabindex="-1">&quot;Mon solde disponible est à 0 alors que j&#39;ai distribué des campagnes&quot; <a class="header-anchor" href="#mon-solde-disponible-est-a-0-alors-que-j-ai-distribue-des-campagnes" aria-label="Permalink to &quot;&quot;Mon solde disponible est à 0 alors que j&#39;ai distribué des campagnes&quot;&quot;">​</a></h3><p>Le solde Wallet ne se crédite <strong>pas automatiquement</strong> après une distribution. Vous devez valider manuellement selon le format :</p><table tabindex="0"><thead><tr><th>Format</th><th>Action requise</th><th>Où sur la plateforme</th></tr></thead><tbody><tr><td>📦 Insertion Colis</td><td>Déclarez les volumes chaque <strong>lundi ou mardi</strong></td><td>Mes Campagnes → campagne → Déclarer le volume</td></tr><tr><td>📧 Emailing (Dédié ou Display)</td><td>Cliquez sur <strong>&quot;Valider la diffusion&quot;</strong> après l&#39;envoi</td><td>Mes Campagnes → campagne → Valider la diffusion</td></tr></tbody></table><p>Sans ces actions, les fonds restent <strong>séquestrés</strong> — la campagne n&#39;est pas comptabilisée.</p><hr><h3 id="mon-solde-est-en-attente-pas-en-disponible" tabindex="-1">&quot;Mon solde est en &#39;attente&#39;, pas en &#39;disponible&#39;&quot; <a class="header-anchor" href="#mon-solde-est-en-attente-pas-en-disponible" aria-label="Permalink to &quot;&quot;Mon solde est en &#39;attente&#39;, pas en &#39;disponible&#39;&quot;&quot;">​</a></h3><p><strong>Cause :</strong> Le délai de protection de 30 jours n&#39;est pas encore écoulé.</p><p>Vos revenus passent par 2 états :</p><ol><li><strong>En attente</strong> : Distribution confirmée, délai de 30 jours en cours</li><li><strong>Disponible</strong> : 30 jours écoulés sans incident → retrait possible</li></ol><blockquote><p><strong>C&#39;est normal.</strong> Ce délai protège tout le monde (vous compris) contre les anomalies post-distribution.</p></blockquote><p>Si vos fonds restent en &quot;attente&quot; après 30 jours → contactez le support avec le numéro de la campagne.</p><hr><h3 id="je-n-ai-pas-recu-mon-virement" tabindex="-1">&quot;Je n&#39;ai pas reçu mon virement&quot; <a class="header-anchor" href="#je-n-ai-pas-recu-mon-virement" aria-label="Permalink to &quot;&quot;Je n&#39;ai pas reçu mon virement&quot;&quot;">​</a></h3><p><strong>Vérifiez dans cet ordre :</strong></p><ol><li><strong>Avez-vous soumis une facture ?</strong> → Sans facture valide jointe à votre demande, le paiement ne part pas.</li><li><strong>Le délai de 30 jours est-il passé ?</strong> → Le solde doit être &quot;Disponible&quot; (pas &quot;En attente&quot;).</li><li><strong>L&#39;IBAN sur votre compte est-il correct ?</strong> → Vérifiez dans Paramètres → Coordonnées bancaires.</li><li><strong>Êtes-vous dans le délai normal ?</strong> → Le paiement est émis à <strong>30 jours fin de mois</strong> après validation de votre demande.</li></ol><p>Si tout est en ordre et le virement est toujours absent → contactez <a href="mailto:support@getinside.io" target="_blank" rel="noreferrer">support@getinside.io</a> avec :</p><ul><li>La date de la demande</li><li>Le montant demandé</li><li>Votre IBAN</li></ul><hr><h3 id="des-frais-de-5-ont-ete-preleves-je-ne-comprends-pas-pourquoi" tabindex="-1">&quot;Des frais de 5% ont été prélevés, je ne comprends pas pourquoi&quot; <a class="header-anchor" href="#des-frais-de-5-ont-ete-preleves-je-ne-comprends-pas-pourquoi" aria-label="Permalink to &quot;&quot;Des frais de 5% ont été prélevés, je ne comprends pas pourquoi&quot;&quot;">​</a></h3><p>Les frais de 5% s&#39;appliquent uniquement pour l&#39;<strong>Offre Starter</strong> à partir du <strong>2ème retrait de l&#39;année civile</strong>.</p><table tabindex="0"><thead><tr><th>Offre</th><th>Frais de retrait</th></tr></thead><tbody><tr><td>Starter</td><td>1er retrait/an : GRATUIT · Suivants : 5%</td></tr><tr><td>Plateforme</td><td>Tous les retraits : GRATUITS</td></tr><tr><td>Managed</td><td>Tous les retraits : GRATUITS</td></tr></tbody></table><p>Si vous êtes sur Plateforme ou Managed et que des frais ont été prélevés → c&#39;est une erreur, contactez le support immédiatement.</p><hr><h3 id="des-fonds-ont-ete-preleves-de-mon-wallet-sans-que-je-l-aie-demande" tabindex="-1">&quot;Des fonds ont été prélevés de mon Wallet sans que je l&#39;aie demandé&quot; <a class="header-anchor" href="#des-fonds-ont-ete-preleves-de-mon-wallet-sans-que-je-l-aie-demande" aria-label="Permalink to &quot;&quot;Des fonds ont été prélevés de mon Wallet sans que je l&#39;aie demandé&quot;&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Pénalités automatiques prélevées sur votre Wallet</p><ul><li><strong>Annulation d&#39;une campagne validée :</strong> pénalité forfaitaire 250€ + frais de plateforme</li><li><strong>Non-réponse sous 48h à une proposition :</strong> pénalité appliquée selon contrat</li><li><strong>Réponse tardive sans motif valable :</strong> peut entraîner une pénalité</li></ul></div><p>Consultez la section <strong>Historique Wallet</strong> sur la plateforme pour voir le détail de chaque mouvement.</p><hr><h3 id="mes-fonds-ont-expire" tabindex="-1">&quot;Mes fonds ont expiré&quot; <a class="header-anchor" href="#mes-fonds-ont-expire" aria-label="Permalink to &quot;&quot;Mes fonds ont expiré&quot;&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Expiration après 12 mois d&#39;inactivité</p><p>Si vous ne vous connectez pas ET ne retirez pas vos fonds pendant 12 mois consécutifs, les fonds disponibles sont définitivement acquis à getinside. Cette règle est contractuelle.</p></div><p><strong>Prévention :</strong> Connectez-vous au moins une fois par trimestre, ou planifiez un retrait annuel.</p><p>Si vous pensez que l&#39;expiration est injustifiée → contactez le support avec vos historiques de connexion.</p><hr><h2 id="📦-campagnes-operations" tabindex="-1">📦 Campagnes &amp; Opérations <a class="header-anchor" href="#📦-campagnes-operations" aria-label="Permalink to &quot;📦 Campagnes &amp; Opérations&quot;">​</a></h2><h3 id="j-ai-accepte-une-campagne-mais-je-ne-peux-plus-l-honorer" tabindex="-1">&quot;J&#39;ai accepté une campagne mais je ne peux plus l&#39;honorer&quot; <a class="header-anchor" href="#j-ai-accepte-une-campagne-mais-je-ne-peux-plus-l-honorer" aria-label="Permalink to &quot;&quot;J&#39;ai accepté une campagne mais je ne peux plus l&#39;honorer&quot;&quot;">​</a></h3><p>Agissez <strong>le plus tôt possible</strong> — les pénalités augmentent avec le temps :</p><ol><li><strong>Contactez immédiatement</strong> votre gestionnaire de compte ou le support</li><li><strong>N&#39;annulez pas</strong> depuis la plateforme sans en avoir discuté au préalable</li><li>Expliquez la situation — une solution alternative est souvent possible (report, remplacement par un autre distributeur)</li></ol><blockquote><p>Plus vous anticipez, plus vous limitez les pénalités. Une annulation au dernier moment est plus coûteuse qu&#39;une annulation anticipée.</p></blockquote><hr><h3 id="je-n-ai-pas-repondu-a-une-proposition-de-campagne-dans-les-48h" tabindex="-1">&quot;Je n&#39;ai pas répondu à une proposition de campagne dans les 48h&quot; <a class="header-anchor" href="#je-n-ai-pas-repondu-a-une-proposition-de-campagne-dans-les-48h" aria-label="Permalink to &quot;&quot;Je n&#39;ai pas répondu à une proposition de campagne dans les 48h&quot;&quot;">​</a></h3><p>La règle des 48h est contractuelle. Si le délai est dépassé :</p><ul><li>La proposition <strong>expire automatiquement</strong> et est envoyée à un autre distributeur</li><li>Une <strong>pénalité peut être appliquée</strong> sur votre Wallet selon votre contrat</li><li>Votre <strong>Score Distributeur</strong> peut être impacté (visibilité réduite sur les prochaines campagnes)</li></ul><p><strong>Pour éviter ça à l&#39;avenir :</strong> Activez les notifications email/SMS depuis vos Paramètres de compte.</p><hr><h3 id="une-campagne-est-incomplete-ou-le-visuel-brief-recu-est-incorrect" tabindex="-1">&quot;Une campagne est incomplète ou le visuel/brief reçu est incorrect&quot; <a class="header-anchor" href="#une-campagne-est-incomplete-ou-le-visuel-brief-recu-est-incorrect" aria-label="Permalink to &quot;&quot;Une campagne est incomplète ou le visuel/brief reçu est incorrect&quot;&quot;">​</a></h3><ol><li>Ne commencez <strong>pas</strong> la distribution sans avoir vérifié le matériel</li><li>Signalez le problème via la plateforme (fiche campagne → Signaler un problème) ou contactez directement votre gestionnaire</li><li>getinside contacte l&#39;annonceur pour corriger — la distribution est mise en pause le temps de la correction</li></ol><hr><h2 id="⚙️-compte-affiliation" tabindex="-1">⚙️ Compte &amp; Affiliation <a class="header-anchor" href="#⚙️-compte-affiliation" aria-label="Permalink to &quot;⚙️ Compte &amp; Affiliation&quot;">​</a></h2><h3 id="mes-commissions-de-parrainage-ne-sont-pas-versees" tabindex="-1">&quot;Mes commissions de parrainage ne sont pas versées&quot; <a class="header-anchor" href="#mes-commissions-de-parrainage-ne-sont-pas-versees" aria-label="Permalink to &quot;&quot;Mes commissions de parrainage ne sont pas versées&quot;&quot;">​</a></h3><p>Le versement des commissions d&#39;affiliation est <strong>suspendu automatiquement</strong> si vous avez des factures impayées auprès de getinside. Régularisez votre situation de facturation pour débloquer les versements.</p><hr><h3 id="mon-compte-est-suspendu-ou-bloque" tabindex="-1">&quot;Mon compte est suspendu ou bloqué&quot; <a class="header-anchor" href="#mon-compte-est-suspendu-ou-bloque" aria-label="Permalink to &quot;&quot;Mon compte est suspendu ou bloqué&quot;&quot;">​</a></h3><p>Causes possibles : factures impayées, non-conformité aux règles de la plateforme, activité suspecte détectée.</p><p>Contactez le support à <a href="mailto:support@getinside.io" target="_blank" rel="noreferrer">support@getinside.io</a> en indiquant votre email de compte et le message d&#39;erreur affiché.</p><hr><h2 id="vous-ne-trouvez-pas-votre-reponse" tabindex="-1">Vous ne trouvez pas votre réponse ? <a class="header-anchor" href="#vous-ne-trouvez-pas-votre-reponse" aria-label="Permalink to &quot;Vous ne trouvez pas votre réponse ?&quot;">​</a></h2><ul><li><strong>Email :</strong> <a href="mailto:support@getinside.io" target="_blank" rel="noreferrer">support@getinside.io</a></li><li><strong>Via la plateforme :</strong> Menu → Support → Nouveau ticket</li></ul><p>Précisez : l&#39;ID de la campagne, le montant en question, et une capture d&#39;écran si possible.</p><hr><p><strong>Voir aussi :</strong> <a href="/handbook/docs/fr/publishers/payouts.html">Gestion des Revenus et Paiements</a> · <a href="/handbook/docs/fr/publishers/onboarding-process.html">Processus d&#39;Onboarding</a></p>',62)])])}const g=t(n,[["render",r]]);export{c as __pageData,g as default};
